// Security middleware
app.use(helmet()); // Add security headers
app.use(morgan('combined')); // Request logging

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.'
});
app.use(limiter);

// Input validation middleware
const validateQueryParams = (req, res, next) => {
  // Whitelist allowed query parameters
  const allowedParams = ['limit', 'offset', 'sort'];
  const requestParams = Object.keys(req.query);

  const invalidParams = requestParams.filter(p => !allowedParams.includes(p));
  if (invalidParams.length > 0) {
    return res.status(400).json({ 
      error: 'Invalid query parameters',
      invalid: invalidParams 
    });
  }

  // Validate parameter values
  if (req.query.limit) {
    const limit = parseInt(req.query.limit, 10);
    if (isNaN(limit) || limit < 1 || limit > 100) {
      return res.status(400).json({ 
        error: 'Invalid limit parameter. Must be between 1 and 100' 
      });
    }
  }

  next();
};

// Health check endpoint
app.get('/health', (req, res) => {
  try {
    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString() 
    });
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Users endpoint with validation
app.get('/users', validateQueryParams, (req, res) => {
  try {
    const limit = Math.min(parseInt(req.query.limit, 10) || 10, 100);

    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    const paginatedUsers = users.slice(0, limit);

    res.json({
      data: paginatedUsers,
      count: paginatedUsers.length,
      total: users.length
    });
  } catch (error) {
    console.error('Error fetching users:', error);
    res.status(500).json({ error: 'Failed to fetch users' });
  }
});

// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Endpoint not found' });
});

// Global error handler (must be last)
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);

  // Don't leak error details in production
  const message = process.env.NODE_ENV === 'production' 
    ? 'Internal server error' 
    : err.message;

